
import Swiper from 'swiper/bundle'; // 全ての機能が入っている
// import Swiper, { Navigation, Pagination } from 'swiper'; // 機能選択



/**
 * フロントページのスライド
 * @param {string} container スライドのクラス名
 * @param {string} pagination ページネーションのクラス名
 * @param {string} next 進むボタンのクラス名
 * @param {string} prev 戻るボタンのクラス名
 */

export function swiperSlideFront(container,pagination,next,prev){
  const option = {
    loop: true,
    autoplay: {
      delay: 2500, // 次のスライドに切り替わるまでの時間（ミリ秒）
      disableOnInteraction: false, // ユーザー操作後に自動再生を止める
    },
    // speed: 400,
    slidesPerView: 1,
    spaceBetween: 0,
    // pagination
    pagination: {
      el: pagination,
      clickable: true,
      type: 'bullets' // bullets || fraction || progressbar
    },
    // Navigation arrows
    navigation: {
      nextEl: next,
      prevEl: prev,
    },
  };
  new Swiper(container, option);
}



