/**
 * サムネイル付きメインスライド
 * @param {string} container スライドのクラス名
 * @param {string} containerThumbnail サムネイルのクラス名
 * @param {string} pagination ページネーションのクラス名
 * @param {string} next 進むボタンのクラス名
 * @param {string} prev 戻るボタンのクラス名
 */
export function swiperThumbnail(container,containerThumbnail,pagination,next,prev){
  // サムネイル
  const optionThumbnail = {
    slidesPerView: 3,
    spaceBetween: 16,
  };
  const swiperThumbs = new Swiper(containerThumbnail, optionThumbnail);

  // メイン
  const option = {
    loop: true,
    // autoplay: true,
    // speed: 400,
    slidesPerView: 1,
    spaceBetween: 0,
    loopAdditionalSlides: 1,
    // pagination
    pagination: {
      el: pagination,
      clickable: true,
      type: 'bullets' // bullets || fraction || progressbar
    },
    // Navigation arrows
    navigation: {
      nextEl: next,
      prevEl: prev,
    },
    thumbs: {
      swiper: swiperThumbs,
    },
    breakpoints: {
      // スライドの表示枚数：500px以上の場合
      576: {
      },
      // 811: {
      // },
      // 1025: {
      // }
      1366: {
        centeredSlides: true,
        slidesPerView: 1.15,
      }
    }
  };
  new Swiper(container, option);
}
